import{c as s,Q as n,j as o,m as e}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"世界生成进阶:密度函数 router、多噪声生物群系与拼图结构","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/16-世界生成进阶-密度函数router多噪声生物群系与拼图结构.md","filePath":"minecraftLearning/16-世界生成进阶-密度函数router多噪声生物群系与拼图结构.md","lastUpdated":1781676649000}'),a={name:"minecraftLearning/16-世界生成进阶-密度函数router多噪声生物群系与拼图结构.md"};function r(i,t,d,l,p,u){return n(),o("div",null,[...t[0]||(t[0]=[e(`<h1 id="世界生成进阶-密度函数-router、多噪声生物群系与拼图结构" tabindex="-1">世界生成进阶:密度函数 router、多噪声生物群系与拼图结构 <a class="header-anchor" href="#世界生成进阶-密度函数-router、多噪声生物群系与拼图结构" aria-label="Permalink to &quot;世界生成进阶:密度函数 router、多噪声生物群系与拼图结构&quot;">​</a></h1><p>第 02 篇讲地形生成时,给的是一套&quot;直觉版&quot;心智:多层噪声叠出高度,坐标加种子确定性出图。那套心智没错,但它停留在 2017 年的 Minecraft。1.18(Caves &amp; Cliffs Part II)把整个世界生成<strong>推倒重写</strong>了一遍,今天真实跑的管线跟第 02 篇的直觉差得很远。</p><p>这一篇就讲重写之后的真实架构。核心就一句话:</p><blockquote><p><strong>1.18 之后,世界生成不再是&quot;几个噪声函数硬编码出高度&quot;,而是一棵数据驱动的密度函数树 + 一个把气候参数映射到生物群系的多维查表。地形、生物群系、洞穴被彻底解耦,各算各的,最后叠在一起。</strong></p></blockquote><p>如果你只记住一件事:<strong>生物群系不再决定地形高度了</strong>。这是 1.18 最反直觉、也最关键的变化。</p><hr><h2 id="一、从-硬编码噪声-到-密度函数-router" tabindex="-1">一、从&quot;硬编码噪声&quot;到&quot;密度函数 router&quot; <a class="header-anchor" href="#一、从-硬编码噪声-到-密度函数-router" aria-label="Permalink to &quot;一、从&quot;硬编码噪声&quot;到&quot;密度函数 router&quot;&quot;">​</a></h2><p>老版本(1.17 及以前)的地形生成大致是:每个生物群系自带一组高度参数(基准高度、起伏度),噪声采样后按生物群系的参数缩放,拼出地表。问题很明显:</p><ul><li>生物群系边界处高度参数突变,需要大量插值去抹平接缝;</li><li>想加一种&quot;悬崖&quot;或&quot;超深洞穴&quot;,得改硬编码逻辑;</li><li>山脉只能跟着某个生物群系走,做不出&quot;一座山横跨好几个生物群系&quot;。</li></ul><p>1.18 的答案是 <strong>density function(密度函数)</strong>。</p><h3 id="密度是什么" tabindex="-1">密度是什么 <a class="header-anchor" href="#密度是什么" aria-label="Permalink to &quot;密度是什么&quot;">​</a></h3><p>把世界想成一个 3D 标量场:空间里每一点 <code>(x, y, z)</code> 都有一个<strong>密度值</strong>。规则极简单:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>density(x, y, z) &gt; 0   →  这一点是实心(放方块,默认石头)</span></span>
<span class="line"><span>density(x, y, z) &lt;= 0  →  这一点是空气(或在海平面下放水)</span></span></code></pre></div><p>地形长什么样,完全由&quot;密度场在哪里翻正负号&quot;决定。地表就是密度场的零等值面(iso-surface)。</p><h3 id="router-把密度场拆成可组合的节点" tabindex="-1">router:把密度场拆成可组合的节点 <a class="header-anchor" href="#router-把密度场拆成可组合的节点" aria-label="Permalink to &quot;router:把密度场拆成可组合的节点&quot;">​</a></h3><p>density function 不是一个巨大公式,而是一棵<strong>可组合的运算节点树</strong>,这套配置叫 <strong>noise router</strong>。节点种类大致是:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>噪声源:    noise / shifted_noise / blend_density ...</span></span>
<span class="line"><span>运算:      add / mul / min / max / abs / clamp / 常数 ...</span></span>
<span class="line"><span>样条:      spline(把一个输入按控制点映射成另一条曲线)</span></span>
<span class="line"><span>特殊:      y_clamped_gradient(随高度线性变化)/ interpolated / cache_* ...</span></span></code></pre></div><p><code>cache_2d</code>、<code>cache_once</code>、<code>flat_cache</code> 这类节点是<strong>性能要害</strong>:同一列、同一区块内反复用到的子表达式被缓存下来,不重复采样噪声。世界生成是 CPU 热点,这些缓存节点决定了它能不能跑得动。</p><p>最关键的一点:<strong>整套 router 是数据驱动的</strong>。它写在 <code>worldgen/noise_settings/*.json</code> 里,是第 11 篇讲的<strong>动态注册表</strong>条目——数据包可以替换、客户端进服时同步。换句话说,<strong>不写一行 Java、改 JSON 就能造一个完全不同地形规则的世界</strong>。1.17 想都不敢想。</p><blockquote><p>反直觉点:<code>overworld</code> 的 router 是一棵相当大的 JSON 树(几百行)。你以为&quot;地形生成&quot;是一段算法,其实它现在更像一份<strong>配置</strong>。算法只是那个&quot;求值 density function 树&quot;的解释器。</p></blockquote><hr><h2 id="二、高度从哪来-continentalness-erosion-weirdness-与样条" tabindex="-1">二、高度从哪来:continentalness / erosion / weirdness 与样条 <a class="header-anchor" href="#二、高度从哪来-continentalness-erosion-weirdness-与样条" aria-label="Permalink to &quot;二、高度从哪来:continentalness / erosion / weirdness 与样条&quot;">​</a></h2><p>密度场的主干靠三个低频噪声塑形,它们就是地形的&quot;骨架参数&quot;:</p><table tabindex="0"><thead><tr><th>参数</th><th>直觉含义</th><th>影响</th></tr></thead><tbody><tr><td><strong>continentalness</strong></td><td>大陆性:离海洋有多&quot;内陆&quot;</td><td>低 → 海洋;高 → 内陆高地</td></tr><tr><td><strong>erosion</strong></td><td>侵蚀度:地势被磨平的程度</td><td>低 → 山脉/崎岖;高 → 平原/平坦</td></tr><tr><td><strong>weirdness</strong></td><td>怪异度(经过 PV 折叠)</td><td>制造山峰山谷的反复、河流</td></tr></tbody></table><p>这三个值不是直接当高度用的,而是喂进一组 <strong>spline(样条)</strong>:样条就是&quot;给一串控制点,把输入插值成输出曲线&quot;。比如 continentalness 经过样条后,在&quot;海洋段&quot;输出很低的基准高度,过了海岸线急剧抬升,内陆段缓慢爬高。erosion 的样条再在此基础上决定这块地是揉成尖山还是压成平原。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>continentalness ─┐</span></span>
<span class="line"><span>erosion ─────────┼─► 多级 spline ─► 基准地表高度 + 起伏</span></span>
<span class="line"><span>weirdness ───────┘                    │</span></span>
<span class="line"><span>                                       ▼</span></span>
<span class="line"><span>                         喂回 density function,决定密度场零点在哪一层</span></span></code></pre></div><p>样条嵌套样条,是 1.18 地形&quot;既有大平原又有尖锐山脊&quot;的来源。调地形,本质就是调这些控制点。</p><hr><h2 id="三、生物群系-6-维气候参数的最近邻查表" tabindex="-1">三、生物群系:6 维气候参数的最近邻查表 <a class="header-anchor" href="#三、生物群系-6-维气候参数的最近邻查表" aria-label="Permalink to &quot;三、生物群系:6 维气候参数的最近邻查表&quot;">​</a></h2><p>这是 1.18 跟老版本心智差别最大的地方。</p><p>老版本:<strong>生物群系决定地形</strong>(沙漠是平的、山地是高的)。 1.18:<strong>地形和生物群系都由噪声独立算出,生物群系只决定&quot;长什么样&quot;(方块、植被、刷怪),不决定高度。</strong></p><p>生物群系由 <strong>multi-noise(多噪声)</strong> 选取。每个点采样 <strong>6 个气候参数</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>temperature      温度</span></span>
<span class="line"><span>humidity         湿度</span></span>
<span class="line"><span>continentalness  大陆性   ← 和地形共用同一个噪声</span></span>
<span class="line"><span>erosion          侵蚀度   ← 和地形共用同一个噪声</span></span>
<span class="line"><span>depth            深度(离地表多深,让同一地表下不同高度是不同群系)</span></span>
<span class="line"><span>weirdness        怪异度   ← 和地形共用同一个噪声</span></span></code></pre></div><p>这 6 个值构成一个 <strong>6 维空间里的坐标</strong>。每个生物群系在这个空间里占一个<strong>矩形区域</strong>(对每个参数给一个区间)。选群系的算法就是:<strong>拿当前点的 6 维坐标,在所有生物群系里找&quot;距离最近&quot;的那个</strong>(实现上是一棵 n 维搜索树)。</p><p>这套设计的威力:</p><ul><li>地形(山/谷)和气候(冷/热/干/湿)<strong>正交</strong>,于是&quot;一座雪山的阳面是针叶林、背面是冻原&quot;这种过去做不到的组合自然出现;</li><li>depth 参与选群系,意味着<strong>同一个 x/z 列,地表是草原、洞里是溶洞群系</strong>——洞穴生物群系(繁茂/滴水石)就是这么来的;</li><li>加一个新生物群系 = 在 6 维空间里划一块没被占的区域,不用碰地形代码。</li></ul><blockquote><p>关键澄清:很多人以为&quot;1.18 山更高&quot;是因为山地生物群系改了。不是。是 continentalness/erosion 的样条把基准高度拉高了,山地群系只是恰好被铺在高的地方。<strong>地形不知道自己脚下是什么生物群系。</strong></p></blockquote><hr><h2 id="四、洞穴与含水层-独立的密度函数" tabindex="-1">四、洞穴与含水层:独立的密度函数 <a class="header-anchor" href="#四、洞穴与含水层-独立的密度函数" aria-label="Permalink to &quot;四、洞穴与含水层:独立的密度函数&quot;">​</a></h2><p>老洞穴是&quot;地表生成完,再用一套蠕虫算法(carver)挖隧道&quot;。1.18 的奶酪洞/面条洞是<strong>直接长在密度场里</strong>的——router 里有专门的噪声节点,在地下把密度压成负值,凿出大空腔(奶酪洞)和细长隧道(面条洞)。它们不是&quot;挖出来的&quot;,而是&quot;密度本来就没填上&quot;。</p><p><strong>含水层(aquifer)</strong> 是配套机制:地下空腔不再默认是空气,而是由一套独立噪声决定<strong>局部水位</strong>——所以你会在洞里遇到孤立的小水潭、小岩浆湖,高度还各不相同。没有含水层的话,深洞要么全空要么全淹,1.18 的&quot;地下湿润感&quot;就是含水层给的。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最终方块 = 主地形密度  ⊕  洞穴密度(把密度往负压)  ⊕  含水层(决定空腔填水/岩浆/空气)</span></span></code></pre></div><p>三套噪声各算各的,最后合成。解耦的代价是 router 更复杂,收益是每一块都能单独调、单独被数据包替换。</p><hr><h2 id="五、结构生成-jigsaw-拼图" tabindex="-1">五、结构生成:jigsaw 拼图 <a class="header-anchor" href="#五、结构生成-jigsaw-拼图" aria-label="Permalink to &quot;五、结构生成:jigsaw 拼图&quot;">​</a></h2><p>地形是连续噪声,<strong>结构是离散的、要&quot;拼&quot;出来的</strong>——村庄、前哨站、远古城市、要塞,走的是完全不同的一套系统:<strong>jigsaw(拼图)</strong>。</p><p>思路像乐高:</p><ol><li>结构由一堆<strong>模板块</strong>组成,每块是一个 <code>.nbt</code> 结构文件(一段预先保存的方块 + 方块实体快照,见第 08 篇 NBT)。</li><li>模板块边缘埋着 <strong>jigsaw 方块</strong>,每个 jigsaw 声明自己的名字和&quot;我能接什么名字&quot;。</li><li>从一个起始块开始,按 jigsaw 接口<strong>递归往外拼</strong>:村庄的&quot;路&quot;接&quot;房子&quot;,房子接&quot;装饰&quot;,直到达到深度上限。每次拼接带随机选择,于是每个村庄都不一样。</li></ol><p>外层还有几层数据驱动配置(都在动态注册表里):</p><table tabindex="0"><thead><tr><th>概念</th><th>作用</th></tr></thead><tbody><tr><td><strong>structure</strong>(<code>worldgen/structure/</code>)</td><td>这个结构是什么类型、用哪套 jigsaw 模板池、能出现在哪些生物群系</td></tr><tr><td><strong>structure_set</strong>(<code>worldgen/structure_set/</code>)</td><td>一组结构的<strong>分布规则</strong>:间距、随机散布、salt(避免不同结构生成位重合)</td></tr><tr><td><strong>template_pool</strong>(<code>worldgen/template_pool/</code>)</td><td>jigsaw 拼接时每个名字能抽到哪些 <code>.nbt</code> 模板、权重多少</td></tr></tbody></table><p><strong>结构在什么时候定下来</strong>:回到第 02/05 篇讲的 chunk <strong>Status 流水线</strong>。结构不是地形长完才放,而是在很早的 <code>structure_starts</code> 阶段就<strong>确定好包围盒和拼图布局</strong>(此时邻居 chunk 可能还没生成),后续 chunk 生成到对应阶段时再把模板块&quot;盖章&quot;进去。这就是为什么村庄能跨好几个 chunk 而不断裂——它的&quot;图纸&quot;在任何一块地表长出来之前就画好了。</p><blockquote><p>反直觉点:结构生成必须<strong>先于</strong>它所占的地表细节,否则跨 chunk 的结构没法保证一致。代价是 chunk 生成有严格的阶段依赖(邻居要先到某阶段),这也是远处区块加载慢、区块加载器要钉住一圈邻居的原因之一(第 05 篇)。</p></blockquote><hr><h2 id="六、和第-02-篇怎么对上" tabindex="-1">六、和第 02 篇怎么对上 <a class="header-anchor" href="#六、和第-02-篇怎么对上" aria-label="Permalink to &quot;六、和第 02 篇怎么对上&quot;">​</a></h2><p>别把这篇当成推翻第 02 篇,而是<strong>同一件事的两层</strong>:</p><table tabindex="0"><thead><tr><th>维度</th><th>第 02 篇(直觉)</th><th>本篇(真实管线)</th></tr></thead><tbody><tr><td>地形</td><td>多层噪声叠出高度</td><td>density function 树求值,密度零点即地表</td></tr><tr><td>高度由谁定</td><td>生物群系参数</td><td>continentalness/erosion/weirdness 经样条,<strong>与生物群系无关</strong></td></tr><tr><td>生物群系</td><td>温湿度二维查表</td><td>6 维气候参数最近邻</td></tr><tr><td>洞穴</td><td>&quot;挖出来&quot;</td><td>独立密度函数直接长出来 + 含水层</td></tr><tr><td>结构</td><td>(没细讲)</td><td>jigsaw 拼图,structure_starts 阶段定图纸</td></tr><tr><td>可改性</td><td>改代码</td><td>改 JSON(动态注册表 + 数据包)</td></tr></tbody></table><p>第 02 篇回答&quot;为什么无限世界不用存、走到哪算到哪&quot;,那套<strong>确定性 = 种子 + 坐标 → 固定输出</strong>的本质没变;本篇只是把&quot;算&quot;这一步,从&quot;几个硬编码噪声&quot;换成了&quot;一棵数据驱动的密度函数树 + 一套解耦的气候/结构系统&quot;。省与快的主线(能算不存)依旧成立,只是算的方式工程化了一大截。</p><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><ul><li>地形 = density function 树求值,密度 &gt; 0 为实心;整棵树是数据驱动的 noise router(JSON,动态注册表)。</li><li>高度由 continentalness/erosion/weirdness 经样条决定,<strong>和生物群系彻底解耦</strong>——1.18 最反直觉的点。</li><li>生物群系 = 6 维气候参数在多维空间里找最近邻,只管&quot;长什么样&quot;,不管高度;depth 维度让地下能有独立洞穴群系。</li><li>洞穴和含水层是独立密度函数,&quot;长出来&quot;而非&quot;挖出来&quot;。</li><li>结构走 jigsaw 拼图:<code>.nbt</code> 模板 + jigsaw 接口递归拼接,structure_set 管分布;在 chunk 的 structure_starts 阶段就定好图纸,所以能跨 chunk 不断裂。</li></ul>`,60)])])}const h=s(a,[["render",r]]);export{g as __pageData,h as default};
